831	            sum = (sum >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
832	            *pOut = NDS_DSP_SATS((sum >> post_rshift), 8);
833	            pOut++;
834	        }
835	    }
836	#endif
837	#elif defined(ENA_DSP_ISA)
838	    int16_t   i_out_y, i_out_x, i_ker_y, i_ker_x;
839	
840	    /*
841	     *  Here we use in_tmp_buf as q15_t internally as computation are done with q15_t level
842	     *  im2col are done to output in q15_t format from q7_t input
843	     */
844	
845	    q15_t    *pBuffer = in_tmp_buf;
846	    q7_t     *pOut = out_tensor;
847	
848	    /*
849	     *  Here we split the entire matrix into three regions depending on the pad situation
850	     *    Top: i_out_y from 0 to pad - 1
851	     * Middle: i_out_y from pad to out_tensor_dim-pad-1
852	     * Bottom: i_out_y from out_tensor_dim-pad to out_tensor_dim-1
853	     */
854	
855	    /* top part */
856	    for (i_out_y = 0; i_out_y < pad; i_out_y++)
857	    {
858	        for (i_out_x = 0; i_out_x < out_tensor_dim; i_out_x++)
859	        {
860	            /* This part implements the im2col function */
861	            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
862	            {
863	                for (i_ker_x = i_out_x * stride - pad; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
864	                {
