880	                pOut =
881	                    nn_mat_mul_kernel_q7_q15_q7_reordered_bias_2sft(ker_weight,
882	                                                                    in_tmp_buf,
883	                                                                    out_tensor_ch,
884	                                                                    in_tensor_ch * ker_dim * ker_dim,
885	                                                                    pre_rshift,
886	                                                                    out_scale,
887	                                                                    post_rshift,
888	                                                                    bias,
