896	    /* middle part, here we also divide the x into left, mid and right */
897	    for (; i_out_y < out_tensor_dim - pad; i_out_y++)
898	    {
899	        /* left part */
900	        for (i_out_x = 0; i_out_x < pad; i_out_x++)
901	        {
902	            /* This part implements the im2col function */
903	            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
904	            {
