1013	                    {
1014	                        memset(pBuffer, 0, sizeof(q15_t)*in_tensor_ch);
1015	                    }
1016	                    else
1017	                    {
1018	                        nn_dup_s8_s16_reordered
1019	                        ((q7_t *) in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
1020	                    }
1021	                    pBuffer += in_tensor_ch;
1022	                }
1023	            }
1024	
1025	            if (pBuffer == in_tmp_buf + 2 * in_tensor_ch * ker_dim * ker_dim)
1026	            {
1027	                pOut =
1028	                    nn_mat_mul_kernel_q7_q15_q7_reordered_bias_2sft(ker_weight,
1029	                                                                    in_tmp_buf,
1030	                                                                    out_tensor_ch,
1031	                                                                    in_tensor_ch * ker_dim * ker_dim,
1032	                                                                    pre_rshift,
1033	                                                                    out_scale,
1034	                                                                    post_rshift,
1035	                                                                    bias,
1036	                                                                    pOut);
1037	                /* counter reset */
1038	                pBuffer = in_tmp_buf;
1039	            }
1040	        }
1041	    }
1042	
1043	    /* check if there is left-over for compute */
1044	    if (pBuffer != in_tmp_buf)
1045	    {
1046	        const q7_t *pA = ker_weight;
1047	        int       i;
1048	
1049	        for (i = 0; i < out_tensor_ch; i++)
1050	        {
1051	            q31_t     sum = bias[i];
1052	            q15_t    *pB = in_tmp_buf;
1053	            /* each time it process 4 entries */
1054	            uint16_t  colCnt = in_tensor_ch * ker_dim * ker_dim >> 2;
1055	
1056	            while (colCnt)
1057	            {
1058	                q31_t     inA1, inA2;
1059	                q31_t     inB1, inB2;
1060	
1061	                pA = (q7_t *) read_and_pad_reordered((void *)pA, &inA1, &inA2);
1062	
1063	                inB1 = *__SIMD32(pB)++;
1064	                sum = NDS_DSP_KMADA(sum, inA1, inB1);
1065	                inB2 = *__SIMD32(pB)++;
1066	                sum = NDS_DSP_KMADA(sum, inA2, inB2);
1067	
1068	                colCnt--;
1069	            }
1070	            //since in_tensor_ch is multiple of 4 (input constraints), the
1071	            //following codes will not be reached
1072	            // colCnt = in_tensor_ch * ker_dim * ker_dim & 0x3;
1073	            // while (colCnt)
1074	            // {
1075	            //     q7_t      inA1 = *pA++;
1076	            //     q15_t     inB1 = *pB++;
1077	            //     sum += inA1 * inB1;
1078	            //     colCnt--;
1079	            // }
1080	            sum = (sum >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
1081	            *pOut++ = NDS_DSP_SATS((sum >> post_rshift), 8);
1082	        }
1083	    }
1084	#else
1085	    uint16_t  i, j, k, l, m, n;
1086	    int       conv_out;
1087	    long in_row, in_col;
1088	
1089	    for (i = 0; i < out_tensor_ch; i++)
1090	    {
1091	        for (j = 0; j < out_tensor_dim; j++)
1092	        {
