                                                      (q7_t*)in_tmp_buf,
                                                      out_tensor_ch,
                                                      in_tensor_ch * ker_dim * ker_dim,
                                                      pre_rshift,
                                                      out_scale,
                                                      post_rshift,
                                                      bias,
