q7_t *nn_mat_mul_kernel_q7_bias_2sft_unroll4(const q7_t * src1,
                                             const q7_t * src2,
                                             const uint16_t out_tensor_ch,
                                             const uint16_t col_src1,
                                             const uint16_t pre_rshift,
                                             const uint16_t out_scale,
