        vint32m1_t vSum2 = __riscv_vredsum(vAccumulator2, vZero, vl);
        vint32m1_t vSum3 = __riscv_vredsum(vAccumulator3, vZero, vl);
        vint32m1_t vSum4 = __riscv_vredsum(vAccumulator4, vZero, vl);

